function ShowPersonal(oi_personal_emp, oi_personal, oi_empresa, flow)
{                                                   
	//alert(flow);
	//alert(oi_personal_emp);
	//alert(oi_personal);
	Ctrl('oi_personal_emp').SetXValue(oi_personal_emp);
	Ctrl('oi_personal').SetXValue(oi_personal);
	Ctrl('oi_empresa').SetXValue(oi_empresa);  
	openNewFlowWait(flow,"initialize","<ID oi_personal=\""+Ctrl('oi_personal').GetXValue()+"\" oi_empresa=\""+Ctrl('oi_empresa').GetXValue()+"\" oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" />",new ObjtectResult(),"M");
}
function PERSONAL()
{              
openNewFlowWait("NucleusRH.Base.Personal.Legajo.flow","ORGANIGRAMA","<ID VALUE=\""+Ctrl('oi_personal').GetXValue()+"\" />",new ObjtectResult(),"L");
}
function PERSONAL_EMP()
{                                                   
openNewFlowWait("NucleusRH.Base.Personal.LegajoEmpresa.flow","ORGANIGRAMA","<ID VALUE=\""+Ctrl('oi_personal_emp').GetXValue()+"\" />",new ObjtectResult(),"L");
}          
function LEGAJO_CLASE()
{                                                   
openNewFlowWait("NucleusRH.Base.Personal.Reportes.LegajosporClase.flow","ORGANIGRAMA","<FILTRO oi_clase_org=\"\" oi_empresa=\""+Ctrl('oi_empresa').GetXValue()+"\"><PERSONAS><PERSONA id=\""+Ctrl('oi_personal_emp').GetXValue()+"\" /></PERSONAS></FILTRO>",new ObjtectResult(),"L");
}
function vencimiento()
{                                                   
openNewFlowWait("NucleusRH.Base.Personal.Reportes.VencimientosEPP.flow","ORGANIGRAMA","<FILTRO f_desde=\"\" f_hasta=\"\" oi_empresa=\""+Ctrl('oi_empresa').GetXValue()+"\" salida=\"HTML\"><PERSONAS><PERSONA id=\""+Ctrl('oi_personal_emp').GetXValue()+"\" /></PERSONAS></FILTRO>",new ObjtectResult(),"L");
}  
function posicion()
{                                                   
