}
function anticipo()
{                                                   
openNewFlowWait("NucleusRH.Base.Liquidacion.Reporte.ListadoAnticipos.flow","REPORTE","<DATOS oi_empresa=\""+Ctrl('oi_empresa').GetXValue()+"\" f_desde_anticipo=\"\" f_hasta_anticipo=\"\" c_estado=\"\" report=\"\"><PERSONAS><PERSONA id=\""+Ctrl('oi_personal_emp').GetXValue()+"\" /></PERSONAS></DATOS>",new ObjtectResult(),"L");
